request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?modelName)), "6e8e") || CONTAINS(LCASE(STR(?origId)), "6e8e") || CONTAINS(LCASE(STR(?normId)), "6e8e"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Check for gateways in the model and their connections
SELECT ?gateway ?gatewayName ?gatewayType ?direction ?sourceName ?targetName WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL {
    ?outEdge bbo:has_sourceRef ?gateway .
    ?outEdge bbo:has_targetRef ?target .
    OPTIONAL { ?target bbo:name ?targetName . }
  }
  OPTIONAL {
    ?inEdge bbo:has_targetRef ?gateway .
    ?inEdge bbo:has_sourceRef ?source .
    OPTIONAL { ?source bbo:name ?sourceName . }
  }
}
LIMIT 50
